:root {
  --card-bg: #1a1a2e;
  --card-border: #e8b86d;
  --header-bg: #16213e;
  --title-color: #e8b86d;
  --subtitle-color: #a89bb0;
  --tag-bg: #e8b86d;
  --tag-color: #1a1a2e;
  --item-border: #2d2d4e;
  --item-featured-bg: #22224a;
  --item-bg: transparent;
  --name-color: #f0e6ff;
  --price-color: #e8b86d;
  --ingredients-color: #8a8aaa;
  --dots-color: #3a3a5e;
  --badge-strong-bg: #4a1942;
  --badge-strong-color: #e88dd4;
  --badge-bitter-bg: #1a3a2e;
  --badge-bitter-color: #6edba8;
  --badge-light-bg: #3a3010;
  --badge-light-color: #f0d060;
  --badge-fruity-bg: #3a1010;
  --badge-fruity-color: #f08080;
  --badge-smoky-bg: #252535;
  --badge-smoky-color: #b0b0d8;
  --badge-spicy-bg: #3a1a10;
  --badge-spicy-color: #f09060;
  --footer-bg: #16213e;
  --footer-note-color: #e8b86d;
  --footer-hours-color: #a89bb0;
}

.menu-card {
  width: 480px;
  background: var(--card-bg);
  border: 2px solid var(--card-border);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.menu-header {
  background: var(--header-bg);
  padding: 16px 24px 14px;
  border-bottom: 1px solid var(--item-border);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.menu-tag {
  display: inline-block;
  background: var(--tag-bg);
  color: var(--tag-color);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 3px 10px;
  border-radius: 20px;
  width: fit-content;
}

.menu-title {
  font-size: 22px;
  font-weight: 800;
  color: var(--title-color);
  margin: 0;
  line-height: 1.2;
}

.menu-subtitle {
  font-size: 12px;
  color: var(--subtitle-color);
  margin: 0;
}

.cocktail-list {
  padding: 10px 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.cocktail-item {
  background: var(--item-bg);
  border: 1px solid var(--item-border);
  border-radius: 10px;
  padding: 10px 14px;
}

.cocktail-item.featured {
  background: var(--item-featured-bg);
  border-color: var(--card-border);
}

.cocktail-info {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}

.cocktail-name {
  font-size: 14px;
  font-weight: 700;
  color: var(--name-color);
  white-space: nowrap;
}

.cocktail-dots {
  flex: 1;
  border-bottom: 2px dotted var(--dots-color);
}

.cocktail-price {
  font-size: 14px;
  font-weight: 700;
  color: var(--price-color);
}

.cocktail-ingredients {
  font-size: 11px;
  color: var(--ingredients-color);
  margin-bottom: 8px;
}

.cocktail-badges {
  display: flex;
  gap: 6px;
}

.badge {
  font-size: 10px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 4px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.badge-strong {
  background: var(--badge-strong-bg);
  color: var(--badge-strong-color);
}

.badge-bitter {
  background: var(--badge-bitter-bg);
  color: var(--badge-bitter-color);
}

.badge-light {
  background: var(--badge-light-bg);
  color: var(--badge-light-color);
}

.badge-fruity {
  background: var(--badge-fruity-bg);
  color: var(--badge-fruity-color);
}

.badge-smoky {
  background: var(--badge-smoky-bg);
  color: var(--badge-smoky-color);
}

.badge-spicy {
  background: var(--badge-spicy-bg);
  color: var(--badge-spicy-color);
}

.menu-footer {
  background: var(--footer-bg);
  border-top: 1px solid var(--item-border);
  padding: 10px 24px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.footer-note {
  font-size: 11px;
  color: var(--footer-note-color);
  font-weight: 600;
}

.footer-hours {
  font-size: 11px;
  color: var(--footer-hours-color);
}
